   242→// getConfigFile provides a file from different types of storage.
   243→func getConfigFile(ctx context.Context, path string) (fs.File, error) {
   244→	u, err := url.Parse(path)
   245→	if err != nil {
   246→		return nil, err
   247→	}
   248→
   249→	if slices.Contains(object.SupportedSchemes(), u.Scheme) {
   250→		key := strings.TrimPrefix(u.Path, "/")
   251→		u.Path = ""
   252→		bucket, err := object.OpenBucket(ctx, u)
   253→		if err != nil {
   254→			return nil, err
   255→		}
   256→		defer bucket.Close()
   257→		bucket.SetIOFSCallback(func() (context.Context, *blob.ReaderOptions) { return ctx, nil })
   258→		return bucket.Open(key)
   259→	}
   260→
   261→	// assumes that the local file is used
   262→	file, err := os.Open(path)
   263→	if err != nil {
   264→		return nil, err
   265→	}
   266→	return file, nil
   267→}
