   337→const wildcard = "*"
   338→
   339→func appendIfNotEmpty(s []string, v ...string) []string {
   340→	for _, vs := range v {
   341→		if vs != "" {
   342→			s = append(s, vs)
   343→		}
   344→	}
   345→
   346→	return s
   347→}
   348→
   349→// bind invokes the supplied function "fn" with each possible set of
   350→// prefixes for the next prefix ("next").
   351→// If the last prefix is "*" then we must search the current environment
   352→// for matching env vars to obtain the potential keys which populate
   353→// the unbound map keys.
   354→func bind(env, prefixes []string, next string, fn func([]string)) {
   355→	// given the previous entry is non-existent or not the wildcard
   356→	if len(prefixes) < 1 || prefixes[len(prefixes)-1] != wildcard {
   357→		fn(appendIfNotEmpty(prefixes, next))
   358→		return
   359→	}
   360→
   361→	// drop the wildcard and derive all the possible keys from
   362→	// existing environment variables.
   363→	p := make([]string, len(prefixes)-1)
   364→	copy(p, prefixes[:len(prefixes)-1])
   365→
   366→	var (
   367→		// makezero linter doesn't take note of subsequent copy
   368→		// nolint https://github.com/ashanbrown/makezero/issues/12
   369→		prefix = strings.ToUpper(strings.Join(append(p, ""), "_"))
   370→		keys   = strippedKeys(env, prefix, strings.ToUpper(next))
   371→	)
   372→
   373→	for _, key := range keys {
   374→		fn(appendIfNotEmpty(p, strings.ToLower(key), next))
   375→	}
   376→}
