   378→// strippedKeys returns a set of keys derived from a list of env var keys.
   379→// It starts by filtering and stripping each key with a matching prefix.
   380→// Given a child delimiter string is supplied it also trims the delimeter string
   381→// and any remaining characters after this suffix.
   382→//
   383→// e.g strippedKeys(["A_B_C_D", "A_B_F_D", "A_B_E_D_G"], "A_B", "D")
   384→// returns ["c", "f", "e"]
   385→//
   386→// It's purpose is to extract the parts of env vars which are likely
   387→// keys in an arbitrary map type.
   388→func strippedKeys(envs []string, prefix, delim string) (keys []string) {
   389→	for _, env := range envs {
   390→		if strings.HasPrefix(env, prefix) {
   391→			env = env[len(prefix):]
   392→			if env == "" {
   393→				continue
   394→			}
   395→
   396→			if delim == "" {
   397→				keys = append(keys, env)
   398→				continue
   399→			}
   400→
   401→			// cut the string on the child key and take the left hand component
   402→			if left, _, ok := strings.Cut(env, "_"+delim); ok {
   403→				keys = append(keys, left)
   404→			}
   405→		}
   406→	}
   407→	return
   408→}
