   425→func (c *Config) validate() error {
   426→	if c.Version != "" {
   427→		if strings.TrimSpace(c.Version) != Version {
   428→			return fmt.Errorf("invalid version: %s", c.Version)
   429→		}
   430→	}
   431→
   432→	if c.Authorization.Required && !c.Authentication.Required {
   433→		return errString("authorization", "requires authentication to also be required")
